mapper.select:
select s.id, s.metric_id, s.stat_dimension, s.dimension_id, s.stat_period, s.stat_time, s.metric_value
from rpt_metric_snapshot s left join rpt_metric_def d on d.id = s.metric_id

    and d.metric_type = #{metricType}
    and s.metric_id = #{metricId}
    and s.stat_dimension = #{statDimension}
    and s.dimension_id = #{dimensionId}
 order by s.stat_time desc limit 100
